import{c as t,Q as o,j as s,m as r}from"./chunks/framework.BPKcPtvA.js";const a="/screenshots/intro-hero-light.png",n="/screenshots/intro-hero-dark.png",g=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1778912818000}'),i={name:"guide/introduction.md"};function d(c,e,h,l,u,p){return o(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Exto Console is the operations hub for the Exto suite. Every product we ship — Exto, Bolo, Canvas, and Faria — is run from here: the customers who use it, the people inside those customer organisations, the environments their data lives in, the releases that ship to them, and the money they pay us.</p><p>Before the Console, this work was scattered across spreadsheets for customer records, ad-hoc scripts to add users to each server, separate dashboards for each product&#39;s usage, and email threads to approve a production deploy. The Console replaces all of it with one platform.</p><p><img src="'+a+'" alt="Exto Console — Admin Dashboard" class="light-only"><img src="'+n+'" alt="Exto Console — Admin Dashboard" class="dark-only"></p><h2 id="what-the-console-does" tabindex="-1">What the Console does <a class="header-anchor" href="#what-the-console-does" aria-label="Permalink to &quot;What the Console does&quot;">​</a></h2><p>The Console is built around four pillars:</p><ol><li><p><strong>Unified customer view.</strong> Account managers open one record and see everything about a customer — tenants, instances, users, plans, meters, contracts, invoices, and payments. No more stitching context together from three tools to prep for a review.</p></li><li><p><strong>Identity across every server.</strong> Add, suspend, or remove a customer&#39;s users across dev, QA, and production in a single action. Push security policies — MFA, password rules, identity-provider bindings — and user attributes to every environment from one screen. The Console is the source of truth; the servers follow.</p></li><li><p><strong>Release orchestration with approvals.</strong> Major, minor, and hotfix releases are cut from the Console. Account managers sign off on the customer-facing side, server admins sign off on the infrastructure side, and each release flows through dev → QA → prod under those gates. Customers see one consolidated changelog across every Exto product they&#39;re entitled to.</p></li><li><p><strong>Automated metering and billing.</strong> Define meters for what you charge for, bind them to plans, assign plans to customers, and the Console computes usage, issues invoices, records payments, and reconciles credits — automatically. Revenue scales without the back office scaling with it.</p></li></ol><h2 id="two-surfaces-two-audiences" tabindex="-1">Two surfaces, two audiences <a class="header-anchor" href="#two-surfaces-two-audiences" aria-label="Permalink to &quot;Two surfaces, two audiences&quot;">​</a></h2><p>The Console exposes two distinct workspaces:</p><ul><li><p>The <strong>Admin Console</strong> is for Exto operators — account managers, server admins, finance, QA admins, platform admins. It exposes everything the platform can do across every customer, every tenant, every instance, every release.</p></li><li><p>The <strong>Customer Portal</strong> is what your customers see when they log in. It is scoped to a single customer, hides operator-only functionality, and is gated by portal roles (owner, admin, member). Customers manage their own users, view their usage and invoices, and read release notes for the products they use.</p></li></ul><p>Both surfaces share the same identity layer, the same release machinery, and the same billing engine — they just present different slices of it.</p><h2 id="how-to-use-this-guide" tabindex="-1">How to use this guide <a class="header-anchor" href="#how-to-use-this-guide" aria-label="Permalink to &quot;How to use this guide&quot;">​</a></h2><p>If you are an Exto operator, start with <a href="./getting-started">Quick Start</a> and then jump into <a href="./admin/">the Admin Console section</a>.</p><p>If you are a customer admin signing in for the first time, read <a href="./account/signing-in">Signing In</a> and the <a href="./portal/">Customer Portal Overview</a>.</p><p>If you want to understand how the pieces fit together before opening the UI, read <a href="./concepts/architecture">Core Concepts</a> end-to-end. Everything else in the guide refers back to those concepts.</p>',15)])])}const f=t(i,[["render",d]]);export{g as __pageData,f as default};
